import { SeedEntry } from "./all-entries";

export const BOOK_CHAPTER_ENTRIES: SeedEntry[] = [
  { category:"leadership", title:"Introduction: Why Start with Why?", content:"The book opens with the question that drives all great leaders: WHY do you do what you do? Most organizations know WHAT they do and HOW they do it, but few can clearly articulate WHY. The WHY is your purpose, cause, or belief — the reason your organization exists. Great leaders like Martin Luther King Jr., Steve Jobs, and the Wright Brothers all thought, acted, and communicated from the inside out — starting with WHY.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "start-with-why", "golden-circle", "purpose"], confidence:0.9 },
  { category:"leadership", title:"Chapter 1: Assume You Know", content:"We make assumptions about why people do what they do. The failed assumptions of companies like TiVo and the success of Apple demonstrate that the traditional approach of manipulating price, promotions, and features is not sustainable. Manipulations (price cuts, promotions, fear tactics) can produce short-term results but rarely build loyalty. The alternative is to inspire — to lead with WHY.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "assumptions", "manipulation"], confidence:0.85 },
  { category:"leadership", title:"Chapter 2: Carrots and Sticks", content:"Manipulations — price, promotions, fear, aspiration, peer pressure — are the default tactics of most organizations. They work in the short term but come at a cost: decreasing trust, increasing stress, and eroding loyalty. The law of diffusion of innovation shows that early adopters buy based on belief, not price. When companies rely too heavily on manipulations, they train customers to respond only to the manipulation, not to the value.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "manipulation", "incentives", "trust"], confidence:0.85 },
  { category:"leadership", title:"Chapter 3: The Golden Circle", content:"The Golden Circle has three layers: WHY (purpose/cause/belief) at the center, HOW (process/values) in the middle, and WHAT (results/products) on the outside. Every organization knows WHAT they do; some know HOW they do it; very few know WHY. Inspired leaders and organizations start with WHY and work outward. People don't buy WHAT you do; they buy WHY you do it. The limbic brain (feelings, trust, loyalty) responds to WHY; the neocortex (rational thought, language) processes WHAT.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "golden-circle", "purpose", "biology"], confidence:0.95 },
  { category:"leadership", title:"Chapter 4: This Is Not Opinion, This Is Biology", content:"The Golden Circle maps directly to brain anatomy. The neocortex (outer layer) corresponds to WHAT — rational thought, language, analysis. The limbic brain (middle two sections) corresponds to WHY and HOW — feelings, trust, loyalty, decision-making. The limbic brain has no capacity for language; it drives gut decisions. This explains why we often make decisions based on feeling (limbic) and then rationalize them with logic (neocortex). Leaders who communicate WHY speak directly to the limbic brain.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "biology", "brain", "limbic", "decision-making"], confidence:0.85 },
  { category:"leadership", title:"Chapter 5: Clarity, Discipline and Consistency", content:"Clarity of WHY comes first — knowing exactly what your purpose is. Discipline is about ensuring HOW you operate stays true to your WHY. Consistency means WHAT you do always aligns with the WHY and HOW. When all three are in balance, trust is built. When they're out of alignment — when WHAT you do contradicts your WHY — trust erodes. The Celera case shows how even with clarity of WHY, lack of discipline and consistency in HOW can destroy an organization.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "clarity", "discipline", "consistency", "trust"], confidence:0.85 },
  { category:"leadership", title:"Chapter 6: The Emergence of Trust", content:"Trust emerges when there is consistency between WHY, HOW, and WHAT. The goal of business is NOT to do business with anyone who wants what you have — it's to do business with people who believe what you believe. Trust is built through consistency over time, even when it's inconvenient. The example of Southwest Airlines: their WHY (freedom) is consistently reflected in HOW (no frills, humor) and WHAT (low fares). When consistency breaks, trust breaks.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "trust", "consistency", "southwest"], confidence:0.85 },
  { category:"leadership", title:"Chapter 7: How a Tipping Point Tips", content:"The diffusion of innovation curve maps onto the Golden Circle. Early adopters (15-18% of the market) buy based on belief — they share your WHY. The early majority and late majority wait for social proof and practical benefits. The tipping point is when belief-based adopters reach critical mass and attract the majority. To reach the tipping point, focus on the early adopters who believe what you believe — not on trying to appeal to everyone. Harley-Davidson created a movement by building a community of believers.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "tipping-point", "diffusion", "early-adopters"], confidence:0.85 },
  { category:"leadership", title:"Chapter 8: Start with WHY, but Know HOW", content:"WHY provides direction, but HOW provides the guardrails. A leader who knows WHY but lacks HOW can inspire but not execute. The relationship between Apple (WHY) and its partners (HOW) — like Wozniak building what Jobs envisioned — shows that WHY and HOW must work together. Great partnerships pair a visionary (WHY) with an operator (HOW). The WHY provides the dream; the HOW provides the structure to make it real.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "vision", "execution", "partnership"], confidence:0.85 },
  { category:"leadership", title:"Chapter 9: Know WHY. Know HOW. Then WHAT?", content:"The WHAT is the tangible result — the product, service, or work. Everything an organization says and does is a WHAT that should prove WHAT they believe (WHY). When the WHAT doesn't align with the WHY, confusion and distrust result. Examples: Volkswagen's emissions scandal (WHAT contradicts WHY). Organizations must audit their WHAT constantly to ensure alignment. The WHAT must be measurable and verifiable; it's the proof of the belief.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "alignment", "what", "proof"], confidence:0.85 },
  { category:"leadership", title:"Chapter 10: Communication Is Not About Speaking, It's About Listening", content:"Leading with WHY requires listening for the WHY in others. Communication is a two-way street. Great leaders create a sense of belonging by listening to their followers' WHYs and creating a shared identity. Symbols, stories, and rituals communicate WHY at an emotional level. The empty chair at the leadership table symbolizes that the customer (the WHY) is always present. Leaders must embody the WHY, not just articulate it.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "communication", "listening", "belonging"], confidence:0.85 },
  { category:"leadership", title:"Chapter 11: When WHY Goes Fuzzy", content:"Success often causes WHY to become fuzzy. As organizations grow, the original purpose can get diluted by scale, process, and bureaucracy. The 'fuzzy WHY' leads to decision paralysis, loss of focus, and a decline in innovation. Microsoft's early success and later struggles illustrate how even market leaders lose their way when they lose sight of their WHY. The key is to constantly revisit and recommit to the founding purpose.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "fuzzy-why", "success", "dilution"], confidence:0.85 },
  { category:"leadership", title:"Chapter 12: Split Happens", content:"When WHY goes fuzzy, splits occur — between the founding vision and execution, between departments, between leadership and employees. The 'why-disconnect' creates silos, politics, and competing agendas. To prevent splits, organizations need a clear WHY that serves as the decision filter for every choice. HOW must be disciplined enough to maintain alignment. When splits happen, the solution is not reorganization — it's rediscovering WHY.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "silos", "alignment", "organization"], confidence:0.85 },
  { category:"leadership", title:"Chapter 13: The Origins of a WHY", content:"A WHY is not created — it is discovered. It comes from your past, your upbringing, your life experiences. The WHY is your authentic purpose — the cause you believe in. Simon Sinek's own WHY discovery: 'To inspire people to do what inspires them so that together we can change the world.' To find your WHY, look back at the moments that shaped you and identify the common thread. The WHY is a statement of purpose rooted in your personal history.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "discovery", "purpose", "authenticity"], confidence:0.85 },
  { category:"leadership", title:"Chapter 14: The New Competition", content:"The competition is not other companies doing similar things — it's the forces that keep people from believing in something. The goal is not to beat competitors but to build a following of people who share your belief. When you compete against yourself (your potential), you win. When you compete against others, you're playing their game. The new competition is about finding people who believe what you believe — and serving them so well they attract others.", sourceType:"book", sourceName:"Start with WHY by Simon Sinek", tags:["sinek", "competition", "belief", "following"], confidence:0.85 },
  { category:"psychology", title:"Prologue: The Habit Cure", content:"Lisa Allen's story is a testament to the power of habit change. Over four years, she quit smoking, lost weight, ran a marathon, and changed her entire life — all by changing one keystone habit (smoking). This demonstrates that habits are not destiny; they can be ignored, changed, or replaced. Understanding how habits work is the key to transforming your life, your company, and your community.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "habits", "change", "keystone"], confidence:0.9 },
  { category:"psychology", title:"Chapter 1: The Habit Loop — How Habits Work", content:"The habit loop consists of three elements: CUE (trigger), ROUTINE (the behavior), and REWARD (the benefit). This neurological pattern is the foundation of every habit. The basal ganglia in the brain stores habits, allowing the rest of the brain to work on more complex tasks. Eugene Pauly's case — a man with severe brain damage who could still form new habits — proved that habits operate independently of conscious memory. To understand your own habits, identify the cue and reward driving the routine.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "habit-loop", "cue", "routine", "reward", "basal-ganglia"], confidence:0.95 },
  { category:"psychology", title:"Chapter 2: The Craving Brain — How to Create New Habits", content:"Craving is what makes habits stick. The cue triggers a craving for the reward, which drives the routine. Claude Hopkins' Pepsodent campaign succeeded not by selling toothpaste, but by creating a craving for the tingling sensation — which became the reward cue. The formula: find a simple and obvious cue, clearly define the rewards, and create a craving for that reward. When the brain starts anticipating the reward, the habit becomes automatic.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "craving", "reward", "anticipation", "automaticity"], confidence:0.9 },
  { category:"psychology", title:"Chapter 3: The Golden Rule of Habit Change", content:"You can't extinguish a bad habit — you can only change it. The Golden Rule: keep the same CUE and same REWARD, but change the ROUTINE. Alcoholics Anonymous uses this principle: the cue (stress/anxiety) triggers the meeting (routine) instead of drinking, providing the same reward (community, relief). Belief in the possibility of change is the crucial ingredient. When people believe change is possible, especially through a community (AA, support groups), transformation becomes sustainable.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "habit-change", "golden-rule", "belief", "community"], confidence:0.9 },
  { category:"psychology", title:"Chapter 4: Keystone Habits — Which Habits Matter Most", content:"Some habits matter more than others. Keystone habits start a chain reaction, changing other habits as they shift. Paul O'Neill transformed Alcoa by focusing on one keystone habit: worker safety. This single focus led to improvements in communication, efficiency, and profitability across the entire company. Keystone habits create small wins that build momentum. To identify keystone habits, look for patterns that have ripple effects: exercise, family dinners, making your bed, or tracking a single metric.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "keystone-habits", "ripple-effect", "small-wins", "alcoa"], confidence:0.9 },
  { category:"psychology", title:"Chapter 5: Starbucks and the Habit of Success", content:"Willpower is the single most important keystone habit for individual success. Starbucks trains employees in willpower through the LATTE method: Listen, Acknowledge, Take action, Thank, Explain. By creating routines for moments of stress (pre-planned responses to cues), willpower becomes automatic. The key insight: willpower is a finite resource that can be strengthened through practice. Pre-planning responses to inflection points (the 'when this happens, I will do this' routine) makes willpower a habit.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "willpower", "starbucks", "latte", "pre-planning"], confidence:0.9 },
  { category:"psychology", title:"Chapter 6: The Power of a Crisis", content:"Crises create opportunities for habit change. When an organization faces a crisis, existing habits are disrupted and leaders can establish new norms. The Rhode Island Hospital case shows how even a small crisis (or the right leader) can reshape organizational culture. Good leaders use crises deliberately — they create a sense of urgency that breaks old habits and makes people receptive to new routines. Crisis + clear direction = organizational transformation.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "crisis", "organizational-change", "leadership"], confidence:0.85 },
  { category:"psychology", title:"Chapter 7: How Target Knows What You Want Before You Do", content:"Retailers like Target use data mining to identify customer habits and predict behavior. Andrew Pole built Target's pregnancy prediction model, which could predict a customer's pregnancy before family members knew. This raises ethical questions about the power of habit-manipulation. Companies analyze purchase patterns to identify habit cues and then target offers accordingly. The power of predictive analytics: once a company knows your habits, they can nudge, shape, and exploit them.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "target", "predictive-analytics", "data-mining", "ethics"], confidence:0.85 },
  { category:"psychology", title:"Chapter 8: How Movements Happen", content:"Social movements start with the habits of friendship (strong ties) and community (weak ties). The Montgomery Bus Boycott succeeded because of the strong ties of the black community (churches, neighborhoods) and the weak ties that spread the message rapidly (the carpool system). Saddleback Church grew through small groups (strong ties creating belonging) and large-scale events (weak ties for growth). Social habits — peer pressure, social proof, and community norms — drive movements. Change happens when communities make it happen together.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "movements", "social-habits", "community", "montgomery"], confidence:0.85 },
  { category:"psychology", title:"Chapter 9: The Neurology of Free Will", content:"If habits are automatic neurological patterns, are we responsible for our actions? The case of Brian Thomas — a man who killed his wife while sleepwalking — raises legal and ethical questions about habit-driven behavior. The answer: habits operate outside conscious awareness, but we are responsible for shaping the routines we install. While we may not choose our initial cues, we can choose our responses. The neurological evidence shows that the brain's prefrontal cortex can override automatic habits — but only with awareness and effort.", sourceType:"book", sourceName:"The Power of Habit by Charles Duhigg", tags:["duhigg", "free-will", "responsibility", "neurology"], confidence:0.85 },
  { category:"psychology", title:"Part 1, Chapter 1: Don't Kick Over the Beehive", content:"Don't criticize, condemn, or complain. Criticism is futile because it puts people on the defensive and makes them strive to justify themselves. Ninety-nine times out of a hundred, people don't criticize themselves for anything, no matter how wrong it is. Instead of condemning others, try to understand them. Understanding breeds sympathy, tolerance, and kindness. The great artist Arturo Toscanini said: 'I have yet to meet a man who could not be improved by a reasonable amount of flattery.'", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "criticism", "understanding", "kindness"], confidence:0.9 },
  { category:"psychology", title:"Part 1, Chapter 2: The Big Secret of Dealing with People", content:"The deepest principle in human nature is the craving to be appreciated. William James said, 'The deepest principle in human nature is the craving to be appreciated.' This craving — the desire to feel important — distinguishes humans from animals. Flattery is insincere; appreciation is sincere. The difference: flattery comes from the teeth, appreciation from the heart. Give honest, sincere appreciation. 'I shall pass this way but once; any good that I can do, let me do it now.'", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "appreciation", "importance", "kindness"], confidence:0.9 },
  { category:"psychology", title:"Part 1, Chapter 3: He Who Can Do This Has the Whole World with Him", content:"The only way to get someone to do anything is to make them WANT to do it. Arouse in the other person an eager want. The key to influence is not to talk about what YOU want, but to show the other person what THEY want and how to get it. Henry Ford's formula: 'If there is any one secret of success, it lies in the ability to get the other person's point of view and see things from that person's angle as well as from your own.'", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "desire", "perspective", "influence"], confidence:0.9 },
  { category:"psychology", title:"Part 2, Chapter 1: Do This and You'll Be Welcome Anywhere", content:"The royal road to a person's heart is to talk about the things they treasure most. Become genuinely interested in other people. The person who is not interested in their fellow human beings has the greatest difficulties in life. If you want others to like you, like them first. Show genuine curiosity about their lives, passions, and challenges. The dog that doesn't bark has no friends; the person who doesn't show interest in others is equally alone.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "interest", "curiosity", "relationships"], confidence:0.9 },
  { category:"psychology", title:"Part 2, Chapter 2: A Simple Way to Make a Good First Impression", content:"Actions speak louder than words — and a smile says, 'I like you. You make me happy. I am glad to see you.' A genuine smile creates a good impression instantly. It brightens the lives of all who see it. To have people like you, smile. Not a forced, fake smile, but a genuine one that reflects your inner attitude. The effect is immediate and powerful. It costs nothing but creates much.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "smile", "first-impression", "warmth"], confidence:0.9 },
  { category:"psychology", title:"Part 2, Chapter 3: Remember Names", content:"Remember that a person's name is the sweetest and most important sound in any language. The ability to remember names is nearly as important as the ability to think. Napoleon III prided himself on remembering every person he met. He would ask about the name, its pronunciation, spell it, write it down, and associate it with something about the person. Using a person's name creates connection, respect, and attention. It signals that you value them as an individual.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "names", "respect", "connection"], confidence:0.9 },
  { category:"psychology", title:"Part 2, Chapter 4: Be a Good Conversationalist", content:"To be a good conversationalist, be a good listener. Encourage others to talk about themselves. Listen more than you speak. Ask questions the other person will enjoy answering. The greatest compliment you can pay anyone is to listen to them — truly listen. Even the most opinionated person will respond positively to a patient, sympathetic listener. People who talk only of themselves think only of themselves. To be interesting, be interested.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "listening", "conversation", "interest"], confidence:0.9 },
  { category:"psychology", title:"Part 2, Chapter 5: How to Interest People", content:"Talk in terms of the other person's interests. The royal road to a person's heart is to discuss the things they treasure most. Theodore Roosevelt astonished everyone who met him by knowing something about each person's particular interest — he would stay up late reading about their field before meeting them. Find out what the other person is passionate about and talk about that. When you speak to someone about what they care about, you immediately become interesting to them.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "interests", "passion", "connection"], confidence:0.9 },
  { category:"psychology", title:"Part 2, Chapter 6: Make People Like You Instantly", content:"Make the other person feel important — and do it sincerely. The desire to feel important is one of the most compelling human drives. John Dewey said the deepest urge in human nature is 'the desire to be important.' To make someone feel important: appreciate what they do, acknowledge their contributions, show respect for their expertise. Everyone wants to feel like they matter. When you make people feel valued, they naturally warm to you. The key is sincerity.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "importance", "appreciation", "value"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 1: You Can't Win an Argument", content:"The only way to get the best of an argument is to avoid it. Nine times out of ten, an argument ends with each participant more convinced than ever that they are right. You can't win an argument because if you lose it, you lose it; and if you win it, you lose it — because you've made the other person feel inferior and hurt their pride. Benjamin Franklin's rule: 'I will speak ill of no man, and speak all the good I know of everybody.'", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "argument", "conflict", "ben-franklin"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 2: Show Respect for Others' Opinions", content:"Never say 'you're wrong.' If you tell someone they're wrong, you strike a direct blow to their intelligence, judgment, pride, and self-respect. That makes them want to strike back. Even if you're right, you can't change their mind by telling them they're wrong. Instead, try to see things from their point of view. Be diplomatic: 'I thought otherwise, but I may be wrong. Let's examine the facts.' Show respect for the other person's opinions.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "respect", "opinions", "diplomacy"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 3: If You're Wrong, Admit It", content:"When you're wrong, admit it quickly and emphatically. Any fool can try to defend their mistakes — but most fools do. Admitting error gets the other person to stop defending and start being reasonable. It creates an atmosphere of forgiveness. By admitting your mistakes, you disarm the other person and demonstrate integrity. Apologize quickly; it takes the wind out of their sails. The cat who's burned once will never go near a hot stove again — and will never go near a cold one either.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "admit-mistakes", "apologize", "integrity"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 4: A Drop of Honey", content:"Begin with praise and honest appreciation. It's always easier to listen to unpleasant things after we've heard some praise of our positive qualities. Like a dentist who begins with Novocain, the patient still gets a drilling but without the pain. Start with sincere appreciation, then lead into the areas for improvement. This approach makes the other person receptive. 'A drop of honey catches more flies than a gallon of gall.' Start friendly, stay warm, and the path opens.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "praise", "appreciation", "feedback"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 5: The Secret of Socrates", content:"Get the other person saying 'yes, yes' immediately. Socrates' method: ask questions the other person must agree with, building a chain of yeses that leads to your conclusion. When someone says 'no,' their whole body goes into a state of resistance. Keep them saying 'yes' and the conversation flows toward agreement. Start with facts they can't disagree with, lead step by step, and let them arrive at your conclusion themselves. Don't tell them — let them discover.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "socrates", "yes", "agreement"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 6: The Safety Valve in Handling Complaints", content:"Let the other person do a great deal of the talking. They know their problems better than you do. So ask questions, let them tell you. When they're talking, they're releasing pressure. Interrupting, arguing, or jumping to solutions shuts the valve. Let them vent, let them explain, let them come to their own conclusions. This approach works because people are more committed to ideas they arrive at themselves. Don't monopolize the conversation; listen more than you speak.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "listening", "complaints", "venting"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 7: How to Get Cooperation", content:"Let the other person feel that the idea is theirs. People will more readily follow a suggestion they believe they came up with themselves. Don't impose your ideas — plant seeds and let them grow. Cooperate by suggesting possibilities and letting others draw conclusions. When someone feels ownership of an idea, they'll work harder to make it succeed. The goal is not to take credit but to achieve the outcome. 'The reason why rivers receive the homage of a hundred mountain streams is that they keep below them.' — Lao Tzu.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "cooperation", "ownership", "ideas"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 8: A Formula That Will Work Wonders", content:"Try honestly to see things from the other person's point of view. Most of us have a tremendous craving for understanding. When you empathize with someone's position, you unlock their defenses. The formula: 'I don't blame you one iota for feeling as you do. If I were you, I would undoubtedly feel the same way.' Understanding doesn't mean agreeing — it means seeing their perspective clearly. From that understanding, real persuasion begins.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "empathy", "perspective", "understanding"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 9: What Everybody Wants", content:"Be sympathetic with the other person's ideas and desires. People are hungry for sympathy — they want you to recognize their desires, hopes, and anxieties. Three words that can transform any disagreement: 'I understand how you feel.' When you validate someone's emotions, you create a bridge. Sympathy doesn't mean you agree; it means you care. Sympathy lubricates the wheels of human interaction. The great tragedies of the world have been caused by people who refused to be sympathetic.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "sympathy", "validation", "emotions"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 10: An Appeal That Everybody Likes", content:"Appeal to nobler motives. People like to feel they're acting from noble, high-minded intentions. Even when they're not, they want to believe they are. J. Pierpont Morgan once explained: 'A man generally has two reasons for doing a thing: one that sounds good and a real one.' You don't need to emphasize the real one. To change people, appeal to the motive that sounds good. Assume the best and watch them rise to it. Appeal to the better angels of their nature.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "nobility", "motives", "idealism"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 11: Dramatize Your Ideas", content:"The modern world is saturated with information. To get your point across, you need to make it vivid, interesting, dramatic. Use stories, examples, demonstrations, visuals. Show, don't just tell. A statistic is abstract; a story about one person is concrete. This is why movies and TV are so powerful — they dramatize. Whatever you're trying to communicate, find a way to make it come alive. A dramatized idea is worth a thousand undramatized ones.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "drama", "storytelling", "demonstration"], confidence:0.9 },
  { category:"psychology", title:"Part 3, Chapter 12: When Nothing Else Works, Try This", content:"Throw down a challenge. The one major factor that motivates people is the desire to excel. People love a challenge. When nothing else works, issue a challenge. Charles Schwab transformed Bethlehem Steel by challenging his managers to beat each other's production records. The thrill of competition, the chance to prove oneself, the opportunity to achieve recognition — these are powerful motivators. 'The way to get things done is to stimulate competition — not in a selfish way, but in a desire to excel.'", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "challenge", "competition", "motivation"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 1: If You Must Find Fault", content:"Begin with praise and honest appreciation before offering criticism. If you must point out a fault, start by acknowledging the other person's strengths. A surgeon doesn't begin an operation without first sterilizing the area. Similarly, minds are more receptive when you start with appreciation. This creates psychological safety and reduces defensiveness. The sandwich method: praise, then constructive feedback, then more praise and encouragement. People accept criticism better when wrapped in genuine appreciation.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "criticism", "feedback", "praise"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 2: How to Criticize Without Being Hated", content:"Call attention to people's mistakes indirectly. Direct criticism creates resentment. Instead, use indirect methods: 'I have an idea that might work better...' or 'What do you think about trying it this way?' Schopenhauer said: 'If you want to win someone to your cause, first convince him that you are his sincere friend.' When you criticize indirectly, you preserve the person's dignity and they're more likely to accept the suggestion. Use suggestion, not accusation.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "indirect-criticism", "suggestion", "dignity"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 3: Talk About Your Own Mistakes First", content:"Before criticizing others, talk about your own mistakes first. Admitting your own errors before pointing out someone else's makes the criticism far less threatening. Charles Schwab once convinced a steel mill manager to stop smoking by first admitting he himself had tried and failed many times. When you acknowledge your own shortcomings, the other person feels understood rather than attacked. It's not humiliation — it's humility. 'My own mistakes have been many. But here's what I learned.'", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "humility", "mistakes", "criticism"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 4: No One Likes to Take Orders", content:"Ask questions instead of giving direct orders. No one likes being told what to do. Instead of saying 'Do this,' try 'What do you think about this?' or 'Would this approach work?' People are more likely to follow through on decisions they helped make. Giving orders creates resistance; asking for input creates engagement. The most effective leaders turn commands into questions. This transforms compliance into commitment.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "questions", "orders", "leadership"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 5: Let the Other Person Save Face", content:"Preserve the other person's dignity. Even when someone is clearly wrong, don't humiliate them. Nothing destroys morale and goodwill faster than public embarrassment. Let them save face by finding a graceful exit. Give them a way to retreat without losing honor. Carnegie: 'I have no right to say or do anything that diminishes a man in his own eyes. What matters is not what I think of him, but what he thinks of himself. Hurting a man in his dignity is a crime.' Always leave a graceful way out.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "dignity", "face-saving", "respect"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 6: How to Spur People On to Success", content:"Praise the slightest improvement and praise every improvement. Be lavish in your praise. People respond to encouragement. William James said: 'The deepest principle in human nature is the craving to be appreciated.' People live up (or down) to the expectations set for them. If you expect more, you get more — IF you praise the steps along the way. Be specific with your praise. 'The clarity of your analysis in section 3 was outstanding.' Specific praise is far more powerful than general.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "praise", "encouragement", "progress", "expectations"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 7: Give a Dog a Good Name", content:"Give people a fine reputation to live up to. If you want someone to improve, treat them as if they already possess the quality you want to develop. Give them a good name and they'll strive to live up to it. This is the Pygmalion effect — people become what you expect them to become. If you tell a child they're lazy, they'll prove you right. If you tell them they're hardworking, they'll rise to meet that expectation. Give a dog a good name and watch it become worthy of it.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "reputation", "expectations", "pygmalion"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 8: Make the Fault Seem Easy to Correct", content:"Use encouragement. Make the fault seem easy to correct. When people feel their shortcomings are insurmountable, they give up. But if you frame the problem as something small and fixable, they'll try. 'I know you can do this — you just need to adjust one small thing.' The key is confidence: show them you believe they can improve. When you express confidence in someone's ability to change, you give them the courage to try. People will try anything if you make it seem achievable.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "encouragement", "growth", "confidence"], confidence:0.9 },
  { category:"psychology", title:"Part 4, Chapter 9: Making People Glad to Do What You Want", content:"Make the other person happy to do what you suggest. If you want someone to do something, frame it so they want to do it. Show them how it benefits them. Make their work sound important and noble, give them a choice, and show appreciation. The most effective leaders delegate with such grace that people feel honored to take on the task. The secret: always understand what the other person really wants, then align your request with their desires. When the task serves their interests, they'll do it gladly.", sourceType:"book", sourceName:"How to Win Friends and Influence People by Dale Carnegie", tags:["carnegie", "motivation", "delegation", "alignment"], confidence:0.9 },
  { category:"negotiation", title:"Chapter 1: The New Rules", content:"Negotiation is not about logic — it's about emotional intelligence. The FBI's hostage negotiation team learned that rational arguments don't work when lives are at stake. The new rules of negotiation: listen more than you talk, use tactical empathy, and understand the other side's emotional drivers. The key skill is not IQ but EQ — reading and responding to emotional undercurrents. The most powerful tool in any negotiation is the ability to make the other person feel heard and understood.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "negotiation", "fbi", "emotional-intelligence"], confidence:0.9 },
  { category:"negotiation", title:"Chapter 2: Be a Mirror", content:"Mirroring is the art of repeating the last 1-3 words someone said, with an upward inflection. It creates instant rapport and encourages elaboration. Mirroring signals that you're listening and want to understand. It buys time and gathers information. The key is to be subtle — not mimicking but reflecting key words. Practice the Late-Night FM DJ Voice: a calm, slow, downward-inflecting tone that creates authority and trust. Silence after mirroring is powerful — let the other person fill it.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "mirroring", "rapport", "listening", "silence"], confidence:0.95 },
  { category:"negotiation", title:"Chapter 3: Tactical Empathy", content:"Tactical empathy is understanding the feelings and mindset of another person in the moment, and hearing what is behind those feelings. Labeling — naming the other person's emotions — is the fastest way to build trust. 'It sounds like you're frustrated.' 'It seems like you're worried about the timeline.' Labels create connection by showing you understand. The formula: use phrases like 'It sounds like...', 'It seems like...', 'I'm hearing that...'. Labeling diffuses negative emotions and amplifies positive ones.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "tactical-empathy", "labeling", "emotions", "trust"], confidence:0.95 },
  { category:"negotiation", title:"Chapter 4: Beware Yes — Master No", content:"'No' is the start of the negotiation, not the end. 'Yes' is often a meaningless commitment — people say yes to be polite or end a conversation. 'No' creates safety and gives the other person control. When they say no, they feel empowered and are more likely to open up. The goal is to get to 'that's right' — the moment when the other person feels truly understood. 'That's right' is more powerful than 'yes' because it indicates genuine agreement. To get there, summarize their position, emotions, and perspective.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "no", "that's-right", "safety", "control"], confidence:0.9 },
  { category:"negotiation", title:"Chapter 5: Trigger the Two Words", content:"The most powerful words in negotiation are 'that's right' (breakthrough) followed by 'you're right' (often means shutting down). To trigger 'that's right': use a summary that includes an accusation audit — listing every terrible thing the other side might say about you before they say it. The accusation audit disarms by acknowledging negative perceptions upfront. When you label all the bad stuff, it loses its power. Then they say 'that's right' and the real negotiation begins.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "that's-right", "accusation-audit", "breakthrough"], confidence:0.9 },
  { category:"negotiation", title:"Chapter 6: Bend Their Reality", content:"People have a powerful need for things to be fair. Use this by framing your offer as fair and reasonable. The 'Fair' technique: when they say something is unfair, label it: 'It seems like you feel this is unfair.' Then use 'What' questions to calibrate: 'What about this feels unfair to you?' Use deadlines strategically — but only real ones. The power of loss aversion: people fear loss twice as much as they value gain. Frame your offer in terms of what they'll lose if they don't accept.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "fairness", "loss-aversion", "deadlines", "reality-bending"], confidence:0.85 },
  { category:"negotiation", title:"Chapter 7: Create the Illusion of Control", content:"Calibrated questions — open-ended 'How' and 'What' questions — give the other person the illusion of control while you steer the conversation. 'How am I supposed to do that?' is a powerful deflecting question. 'What about this is important to you?' 'How can I help to make this better for us?' These questions force the other person to solve your problem. Avoid 'Why' questions — they sound accusatory. The right question at the right time can transform conflict into collaboration.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "calibrated-questions", "control", "how", "what"], confidence:0.9 },
  { category:"negotiation", title:"Chapter 8: Guarantee Execution", content:"To guarantee execution, use the 'Rule of Three': get the other person to agree to the same thing three times in different ways. Liars use more words and more complex sentences. The 'Ping' technique: ask something you already know the answer to — if they lie, you've caught them. The 'How' question reveals commitment: 'How will we deal with problems if they arise?' The person who gives a good 'How' answer is committed. Use 'No' to test: 'Is there any reason we can't move forward?' If they can't say no, their yes is meaningless.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "execution", "liars", "rule-of-three", "commitment"], confidence:0.85 },
  { category:"negotiation", title:"Chapter 9: Bargain Hard", content:"The Ackerman model is a bargaining system: 1) Set your target price, 2) Offer 65% of target, 3) Go up to 85%, 4) Go up to 95%, 5) Go up to 100%, 6) Use an exact, non-round number (e.g., $4,527 not $4,500) to signal careful calculation. At each stage, use increasing reluctance. 'I don't know if we can do that...' The key is willingness to walk away. Bargaining is about psychology, not math. Use the Pinocchio effect: liars use more words. Keep them talking and they'll reveal their true position.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "ackerman", "bargaining", "price", "reluctance"], confidence:0.85 },
  { category:"negotiation", title:"Chapter 10: Find the Black Swan", content:"Black Swans are unknown unknowns — pieces of information that completely change the negotiation when discovered. They're hidden desires, unspoken fears, and undiscovered constraints that can unlock deadlocks. To find Black Swans: 1) Listen for verbal and non-verbal cues that contradict the narrative, 2) Notice what they repeatedly avoid, 3) Understand their core beliefs, 4) Identify their unspoken constraints. A Black Swan discovery created the Camp David Accords. The key: remain open to the possibility that you don't know what you don't know.", sourceType:"book", sourceName:"Never Split the Difference by Chris Voss", tags:["voss", "black-swan", "unknown-unknowns", "breakthrough"], confidence:0.85 },
  { category:"psychology", title:"Chapter 1: What Are Emotions For?", content:"Emotions are not obstacles to rational thought — they are essential guides for survival and decision-making. Each emotion prepares the body for a different response: anger pumps blood to hands, fear sends blood to legs, happiness increases energy. Without emotions, we cannot make even simple decisions. Damasio's studies of patients with damaged emotional centers show they become incapable of making rational choices. Reason and emotion are partners, not opponents.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "emotions", "evolution", "decision-making"], confidence:0.9 },
  { category:"psychology", title:"Chapter 2: Anatomy of an Emotional Hijacking", content:"The amygdala is the brain's emotional sentinel. When it detects a threat, it can hijack the brain's normal functions before the neocortex even knows what's happening. This 'amygdala hijack' explains why we snap, freeze, or explode before thinking. The thalamus-amygdala pathway allows quick-and-dirty reactions but can trigger false alarms. Emotional self-awareness is the first step to managing these hijacks. The neocortex processes slowly; the amygdala acts instantly.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "amygdala", "hijack", "neocortex", "self-awareness"], confidence:0.9 },
  { category:"psychology", title:"Chapter 3: When Smart Is Dumb", content:"IQ contributes only about 20% to life success — the rest depends on emotional intelligence. People with high IQs can fail spectacularly while average-IQ people thrive. Academic intelligence has no connection to emotional life. Emotional intelligence includes: self-awareness, self-regulation, empathy, and social skill. These abilities are distinct from but complementary to cognitive intelligence. A high-IQ person who can't manage emotions will underperform someone with average IQ but high EQ.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "iq", "eq", "success", "self-awareness"], confidence:0.9 },
  { category:"psychology", title:"Chapter 4: Know Thyself", content:"Self-awareness is the cornerstone of emotional intelligence. It means recognizing a feeling as it happens — moment-to-moment awareness of your emotional state. People certain of their feelings are better pilots of their lives. Self-awareness can be cultivated through mindfulness, reflection, and paying attention to bodily signals (racing heart, tight chest, flushed face). Three styles: 1) Self-aware (aware of moods as they happen), 2) Engulfed (overwhelmed), 3) Accepting (resigned). Self-awareness enables self-management.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "self-awareness", "mindfulness", "emotional-awareness"], confidence:0.9 },
  { category:"psychology", title:"Chapter 5: Passion's Slaves", content:"Managing emotions — especially distressing ones — is essential for well-being. The goal is not to suppress emotions but to balance them. Key techniques: 1) Self-awareness (catching the feeling early), 2) Cognitive reframing (changing thoughts that drive the emotion), 3) Distraction, 4) Soothing practices (deep breathing, meditation). Anger is the most seductive negative emotion. The antidote: defuse it early before it escalates. The 6-second rule: the emotional brain's refractory period is about 6 seconds. Counting to 10 actually works.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "self-regulation", "anger", "distress", "reframing"], confidence:0.85 },
  { category:"psychology", title:"Chapter 6: The Master Aptitude", content:"Self-motivation — marshaling emotions in the service of a goal — is a master aptitude. Delaying gratification and stifling impulsiveness underlies all accomplishment. The Marshmallow Test showed that four-year-olds who could wait 15 minutes grew up to be more successful, confident, and dependable. Delay of gratification is a learned skill. Flow — complete absorption in an activity — is the ultimate state of motivation. Flow happens when challenge matches skill. To find flow, seek tasks at the edge of your ability.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "motivation", "delayed-gratification", "flow", "marshmallow-test"], confidence:0.9 },
  { category:"psychology", title:"Chapter 7: The Roots of Empathy", content:"Empathy is the foundation of social awareness — the ability to know how another person feels. It builds on self-awareness: the more open we are to our emotions, the more skilled we are at reading others. Empathy develops through: 1) Emotional contagion (automatic mimicry), 2) Self-awareness (distinguishing our feelings from theirs), 3) Perspective-taking (actively imagining their experience). Lack of empathy is the root of cruelty and sociopathy. Empathy is not agreement — it's understanding.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "empathy", "social-awareness", "emotional-contagion"], confidence:0.9 },
  { category:"psychology", title:"Chapter 8: The Social Arts", content:"Social competence — effectively managing relationships — is the culmination of emotional intelligence. It builds on self-awareness, self-regulation, motivation, and empathy. Social skills include: 1) Organizing groups (leadership), 2) Negotiating solutions (conflict resolution), 3) Personal connection (empathy in action), 4) Social analysis (reading situations). People who excel at these make effective leaders and collaborators. Managing others' emotions — soothing distress, inspiring motivation, building rapport — is the highest form of social intelligence.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "social-skills", "leadership", "charisma", "rapport"], confidence:0.9 },
  { category:"psychology", title:"Chapter 9: Intimate Enemies", content:"Emotional intelligence in intimate relationships. Managing conflict, expressing feelings constructively, and maintaining connection are crucial for relationship success. Men and women often have different emotional styles. The key is not avoiding conflict but handling it well. Four destructive patterns (Gottman): Criticism, Contempt, Defensiveness, Stonewalling. Healthy relationships require emotional repair attempts — small gestures that de-escalate tension. The magic ratio: 5 positive interactions for every negative one.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "relationships", "conflict", "gottman", "gender"], confidence:0.85 },
  { category:"psychology", title:"Chapter 10: Managing with Heart", content:"Emotional intelligence in leadership. The best leaders combine IQ with EQ. In the workplace, EQ determines who gets hired, promoted, and succeeds. Key findings: 1) Criticism should be specific and constructive, not personal, 2) Empathy reduces turnover and increases productivity, 3) Self-aware leaders make better decisions, 4) Socially skilled managers build cohesive teams. Companies that invest in EQ training see measurable improvements. The emotional competence of leaders cascades through the entire organization.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "leadership", "management", "workplace", "eq"], confidence:0.85 },
  { category:"psychology", title:"Chapter 11: Mind and Medicine", content:"Emotions have a direct impact on physical health. Chronic anger, anxiety, and depression weaken the immune system. Stress hormones (cortisol, adrenaline) suppress immune function when chronically elevated. Positive emotions — hope, optimism, connection — boost immune function. Patients with high EQ recover faster from surgery. The mind-body connection is biological, not mystical. Managing emotions is as important to health as diet and exercise. Psychoneuroimmunology studies these connections.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "health", "stress", "immune", "mind-body"], confidence:0.85 },
  { category:"psychology", title:"Chapter 12: The Family Crucible", content:"Emotional learning begins in the family. Parents are children's first emotional coaches. Three parenting styles: 1) Ignoring (dismissing feelings), 2) Disapproving (criticizing emotional expression), 3) Coaching (validating and guiding feelings). Emotion-coaching parents raise children with higher EQ. The key moments are 'emotional moments' — when a child is upset, angry, or scared. These are opportunities for connection. Parents who validate feelings while setting boundaries raise emotionally competent children.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "parenting", "family", "emotional-coaching", "children"], confidence:0.85 },
  { category:"psychology", title:"Chapter 13: Trauma and Emotional Relearning", content:"Trauma can rewire the emotional brain, creating hypervigilance, flashbacks, and dysregulation. PTSD is a disorder of the emotional memory system — the amygdala becomes hypersensitive. But the brain remains plastic throughout life; emotional relearning is possible. Key approaches: 1) Exposure therapy, 2) EMDR, 3) Cognitive reappraisal. Emotional healing requires new learning — experiencing new emotional responses in safe contexts. The emotional brain can be retrained at any age.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "trauma", "ptsd", "emotional-learning", "plasticity"], confidence:0.85 },
  { category:"psychology", title:"Chapter 14: Temperament Is Not Destiny", content:"Temperament — our inborn emotional dispositions — is not fixed. While we have genetic tendencies (shyness, reactivity, optimism), brain plasticity means we can reshape our responses. Kagan's studies of shy children showed temperament can be modified by experience. Key factors: 1) Early intervention, 2) Consistent supportive environment, 3) Repeated practice. A shy child can learn social comfort. An angry person can learn calm. Temperament provides the starting point, not the destination. EQ can be learned at any age.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "temperament", "plasticity", "change", "shyness"], confidence:0.85 },
  { category:"psychology", title:"Chapter 15: The Cost of Emotional Illiteracy", content:"Emotional illiteracy has severe social costs. Rising depression, violence, anxiety, and addiction are linked to declining emotional skills. Emotionally illiterate youth are more likely to: drop out, engage in violence, develop substance abuse, and suffer depression. The epidemic of loneliness partly reflects failure of emotional education. Schools that teach emotional literacy see dramatic improvements in behavior and academic performance. The solution: teach emotional skills as systematically as math and reading.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "emotional-illiteracy", "depression", "violence", "education"], confidence:0.85 },
  { category:"psychology", title:"Chapter 16: Schooling the Emotions", content:"Emotional literacy programs produce measurable benefits: reduced aggression, improved academics, better mental health, and stronger relationships. The Self Science curriculum teaches: self-awareness, decision-making, managing feelings, handling stress, empathy, communication, assertiveness, group dynamics, and conflict resolution. Programs work best when integrated into the regular curriculum, teachers are trained, parents are involved, and skills are practiced consistently. EQ can be taught — the question is whether we choose to teach it.", sourceType:"book", sourceName:"Emotional Intelligence by Daniel Goleman", tags:["goleman", "emotional-literacy", "education", "self-science", "curriculum"], confidence:0.85 },
  { category:"behavioral-economics", title:"Introduction: How an Injury Led Me to Irrationality", content:"Dan Ariely's devastating injury during college sparked his interest in irrational behavior. Watching nurses remove bandages — discovering that slow removal was more painful than fast — revealed that framing matters enormously. This book explores the systematic, predictable ways humans are irrational. Unlike Freudian irrationality, behavioral economics shows we make the same irrational mistakes repeatedly — predictably. The research reveals that we are not only irrational but predictably so.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "behavioral-economics", "irrationality", "framing"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 1: The Truth about Relativity", content:"People rarely choose things in absolute terms — we compare. The Economist experiment: people chose between web-only ($59), print-only ($125), and print+web ($125). Most chose print+web because the print-only option was a decoy. Decoys make one option seem obviously better. Relativity explains everything from real estate to salary satisfaction. The key: we're predictably irrational in how we compare. To break free: be aware of decoys and focus on absolute value rather than comparative.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "relativity", "decoy", "comparison", "options"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 2: The Fallacy of Supply and Demand", content:"Prices are determined by arbitrary anchors, not pure supply and demand. The anchoring effect: the first price we encounter becomes a powerful reference point. Students who wrote the last two digits of their SSN next to items then bid on them showed a strong correlation — high-SSN students bid 200-300% more. Arbitrary anchors shape our willingness to pay. Once we've paid a price, that becomes the reference for future purchases. The market is far more arbitrary than we think.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "anchoring", "pricing", "supply-and-demand", "ssn"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 3: The Cost of Zero Cost", content:"Free is a special price. When something is free, we overreact — we grab it even when it's not what we want. The difference between $0 and a few cents is far more powerful than the difference between a few dollars and a few more. Amazon's free shipping experiment: when they lowered the threshold to $0, orders actually went up. Free creates an irrational emotional response — we perceive no risk. Always ask: do I really need this free item, or is the cost (time, attention) actually higher?", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "free", "zero", "pricing", "risk"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 4: The Cost of Social Norms", content:"We live in two worlds: social norms (warm, fuzzy, community) and market norms (cold, transactional, price-based). Mixing them destroys the relationship. A daycare fined parents for late pickup — and MORE parents became late because the fine turned a social obligation into a market transaction. Free gifts build relationships; cash turns friends into vendors. In business, keeping things in the social realm builds loyalty. But once market norms are introduced, you can't go back to social norms.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "social-norms", "market-norms", "pricing", "relationships"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 5: The Influence of Arousal", content:"People vastly underestimate how much emotions affect decision-making. In a 'cold' state (calm, rational), people can't imagine how they'll behave in a 'hot' state (aroused, emotional). Ariely's experiment: college men answered questions about sexual behavior while aroused vs. calm — the difference was staggering. This 'empathy gap' explains why people make bad decisions when emotional. Never make important decisions in a hot emotional state. Wait until you're cold.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "arousal", "empathy-gap", "emotions", "decision-making"], confidence:0.85 },
  { category:"behavioral-economics", title:"Chapter 6: Procrastination and Self-Control", content:"We systematically fail at self-control — we know what we should do but don't. The solution is not willpower but pre-commitment. Students who set their own deadlines performed better than those with no deadlines. But self-imposed deadlines need teeth — real consequences for missing them. Credit cards exploit our self-control failure by separating the pleasure of buying from the pain of paying. Solutions: pre-commitment devices, deadlines with penalties, and limiting future options to prevent bad choices.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "procrastination", "self-control", "deadlines", "pre-commitment"], confidence:0.85 },
  { category:"behavioral-economics", title:"Chapter 7: The High Price of Ownership", content:"We overvalue what we own (the endowment effect). Once you own something, its value increases dramatically. Duke basketball ticket experiment: lottery winners valued tickets at $2,400+; non-winners valued them under $200. Ownership changes perspective: 1) We fall in love with what we have, 2) We focus on potential loss rather than gain, 3) We assume others see the same value. Virtual ownership — '30-day money-back guarantees' — triggers this before you've even paid.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "ownership", "endowment-effect", "loss-aversion", "value"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 8: Keeping Doors Open", content:"Humans hate closing doors. We keep options open even when they cost time, money, and focus. Ariely's 'door game': students who could click to make doors disappear earned more than those who had to keep all doors open. But those keeping doors open were most distracted and earned least. We chase meaningless options because we fear commitment. Closing doors is not failure — it's strategy. Eliminate options that don't serve your primary goal. Focus beats optionality.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "options", "focus", "commitment", "doors"], confidence:0.85 },
  { category:"behavioral-economics", title:"Chapter 9: The Effect of Expectations", content:"Expectations shape our experience. When we expect something good, we experience it as better. The Pepsi Challenge: blind tests preferred Pepsi; with labels, they preferred Coke. Brand expectations overrode actual taste. The brain's pleasure centers respond to expectations, not just reality. Wine in a $50 bottle tastes better than the same wine in a $5 bottle. Price, branding, presentation all shape expectations — and therefore our actual experience. Manage expectations carefully; they create reality.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "expectations", "branding", "placebo", "perception"], confidence:0.9 },
  { category:"behavioral-economics", title:"Chapter 10: The Power of Price", content:"Price affects not just demand but actual efficacy. A $0.50 aspirin works better than a $0.01 aspirin — even when identical. People who paid full price for an energy drink solved more puzzles than those who got a discount — the 'price placebo effect.' Higher price signals higher quality, changing our actual experience. Implications: 1) Discounting may reduce effectiveness, 2) Premium pricing can increase results, 3) The price-quality relationship is a self-fulfilling prophecy.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "price", "placebo", "expectations", "efficacy"], confidence:0.85 },
  { category:"behavioral-economics", title:"Chapter 11: The Context of Our Character, Part I", content:"Dishonesty is influenced by context, not just moral character. People cheat a little — enough to benefit but not enough to feel unethical. Ariely's matrix experiments: people cheated by 1-2 extra puzzles. But when reminded of the Ten Commandments or asked to write the honor code, cheating dropped to zero. Moral reminders work — even for non-religious people. Distance from cash increases cheating: people are more dishonest with tokens than money. Small ethical reminders prevent big lapses.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "dishonesty", "ethics", "cheating", "moral-reminders"], confidence:0.85 },
  { category:"behavioral-economics", title:"Chapter 12: The Context of Our Character, Part II", content:"Cash makes us more honest. The further from actual currency, the more dishonest we become. Credit cards, expense accounts, and insurance claims have higher dishonesty because the link to money is indirect. 'Cash is the mother's milk of honesty.' The solution: bring situations back to cash. When you pay in cash, you think twice. Insurance deductibles should feel as painful as personal spending. Distance from cash enables moral flexibility. Connect decisions to real money.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "cash", "honesty", "credit-cards", "ethics"], confidence:0.85 },
  { category:"behavioral-economics", title:"Chapter 13: Beer and Free Lunches", content:"Behavioral economics shows there ARE free lunches. Understanding our irrational patterns allows us to design better choices. Key takeaways: 1) Decoys guide better decisions, 2) Pre-commitment solves procrastination, 3) Social norms build better relationships than market norms, 4) Closing doors improves focus, 5) Moral reminders improve honesty. We are predictably irrational — and this predictability gives us the power to design environments for better outcomes. Harness irrationality, don't fight it.", sourceType:"book", sourceName:"Predictably Irrational by Dan Ariely", tags:["ariely", "behavioral-economics", "free-lunch", "decision-design"], confidence:0.85 },
  { category:"sales", title:"Chapter 1: We're All in Sales Now", content:"Everyone sells — persuading, influencing, and convincing others. Whether you're a doctor convincing a patient, a teacher engaging students, or an entrepreneur pitching investors — you're in sales. The old view (pushy, manipulative, closing-focused) is obsolete. Today's selling is about 'moving others' — helping people see new possibilities. The key shift: from caveat emptor (buyer beware) to caveat venditor (seller beware). Buyers have more information than ever.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "sales", "moving-others", "persuasion"], confidence:0.9 },
  { category:"sales", title:"Chapter 2: Entrepreneurship, Elasticity, and Ed-Med", content:"Three forces have transformed sales: 1) Entrepreneurship — more people run their own businesses and must constantly sell, 2) Elasticity — frequent job changes require selling yourself to new employers, 3) Ed-Med — education and healthcare (where professionals 'sell' ideas) are the fastest-growing sectors. These forces mean that even people who never identified as 'salespeople' must now master moving others. Sales is no longer a department — it's a skill for everyone.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "entrepreneurship", "ed-med", "elasticity", "trends"], confidence:0.85 },
  { category:"sales", title:"Chapter 3: From Caveat Emptor to Caveat Venditor", content:"Information asymmetry has flipped. Buyers have instant access to reviews, comparisons, and expert analysis. They don't need sellers for information — they need them for interpretation, curation, and guidance. The new role of the seller: 1) Curator — helping buyers make sense of overwhelming options, 2) Connector — building relationships, 3) Problem-solver — understanding real needs. The seller's job is no longer to close a deal but to open a relationship. Sell by serving, not by pushing.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "information-asymmetry", "curator", "connector", "problem-solver"], confidence:0.85 },
  { category:"sales", title:"Chapter 4: Attunement", content:"Attunement is bringing yourself into harmony with others. It's perspective-taking — seeing the world through others' eyes. Those who take another's perspective perform better in persuasion. Three keys: 1) Increase power by reducing it — powerful people are worse at perspective-taking, 2) Ask 'What's this person feeling?' not 'What am I feeling?', 3) Strategic mimicry — subtle mirroring builds rapport. Attunement is not agreement — it's understanding. The opposite is egocentrism.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "attunement", "perspective-taking", "power", "rapport"], confidence:0.9 },
  { category:"sales", title:"Chapter 5: Buoyancy", content:"Selling involves constant rejection. Buoyancy is staying afloat in an ocean of rejection. Research shows explanatory style — how you explain setbacks — determines resilience. Optimistic salespeople outsell pessimistic ones. Three components: 1) Pre-encounter positivity — power posing or self-affirmation before interactions, 2) During-encounter — interrogative self-talk ('Can I make this sale?') is more motivating than declarative, 3) Post-encounter — reframe rejection as information. The 3:1 positivity ratio is the tipping point for team performance.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "buoyancy", "resilience", "rejection", "optimism", "self-talk"], confidence:0.9 },
  { category:"sales", title:"Chapter 6: Clarity", content:"Clarity is making sense of ambiguous situations — seeing what others don't see and solving problems they don't know they have. The premium is not on information access but on pattern-finding and insight. Move from problem-finding to problem-solving. Ask: 'What problem are we really trying to solve?' Clarity means: 1) Zooming out to the big picture, 2) Distilling complexity into simplicity, 3) Helping customers articulate unexpressed needs. The old approach was providing answers; the new approach is finding the right questions.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "clarity", "problem-solving", "insight", "curation"], confidence:0.9 },
  { category:"sales", title:"Chapter 7: Pitch", content:"The old elevator pitch is dead. Today's pitches are shorter, more interactive, and more creative. Six new pitches: 1) The One-Word Pitch (e.g., Volvo = safety), 2) The Question Pitch (provokes curiosity), 3) The Rhyming Pitch (memorable), 4) The Subject-Line Pitch (email opens), 5) The Twitter Pitch (140 characters), 6) The Pixar Pitch (story structure: Once upon a time... Every day... Until one day... Because of that... Until finally...). The common thread: brevity, specificity, emotional connection.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "pitch", "storytelling", "pixar", "brevity"], confidence:0.85 },
  { category:"sales", title:"Chapter 8: Improvise", content:"Nothing goes exactly as planned. Improvisation is essential. Four improv rules for selling: 1) 'Yes, and...' — accept what they offer and build on it, 2) Make your partner look good — mutual benefit not winning, 3) Don't try to be funny — be present and authentic, 4) Listen — truly listen and respond, not to your script. The best sales conversations are improvised, not scripted. But improvisation requires preparation — knowing your material so well you can go off-script at any moment. Structure creates freedom.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "improv", "yes-and", "listening", "presence"], confidence:0.85 },
  { category:"sales", title:"Chapter 9: Serve", content:"The ultimate principle: serve. If you serve others, you'll sell more. Two principles: 1) Make it personal — if you can't help, connect them to someone who can. Serve by pointing to the right solution, even if not yours. 2) Make it purposeful — connect your work to a larger mission. The most successful salespeople are motivated not by money but by making a difference. The paradox: when you stop trying to sell and start trying to serve, you sell more. Service before self.", sourceType:"book", sourceName:"To Sell Is Human by Daniel H. Pink", tags:["pink", "service", "purpose", "altruism", "trust"], confidence:0.9 },
  { category:"business", title:"Introduction: Navigating Cultural Differences", content:"In global business, cultural differences are invisible barriers. The Culture Map provides a framework for how national cultures differ across eight scales. The problem is not that cultures are different — it's that we don't realize how different they are. We assume others think like us. The key insight: there's no right or wrong culture — only different ways of seeing. Success in global business requires understanding these differences and adapting accordingly.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "culture", "global-business", "framework", "introduction"], confidence:0.9 },
  { category:"business", title:"Chapter 1: Communicating Across Cultures", content:"Cultures range from high-context (implicit) to low-context (explicit). In low-context cultures (US, Germany, Scandinavia), good communication is precise and clear. In high-context cultures (Japan, China, Arab countries), much is conveyed through context — body language, tone, status, and what is NOT said. The problem: low-context communicators in high-context cultures miss subtle signals; high-context communicators in low-context cultures feel bluntness as rudeness. Learn to read context and adjust.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "communication", "high-context", "low-context", "explicit"], confidence:0.9 },
  { category:"business", title:"Chapter 2: Evaluating Performance Across Cultures", content:"Cultures differ in how they give negative feedback — from direct (Israel, Netherlands, Germany) to indirect (Japan, China, Thailand). In direct cultures, 'yes' means agreement; in indirect cultures, 'yes' might mean 'I heard you.' The British use 'quite interesting' to mean 'I'm not impressed' while Americans hear it as 'somewhat interesting.' Two dimensions: 1) Direct vs. indirect evaluation, 2) Self-enhancing vs. self-effacing. Leaders must decode and adapt feedback across cultures.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "feedback", "evaluation", "face", "indirect"], confidence:0.9 },
  { category:"business", title:"Chapter 3: The Art of Persuasion", content:"Cultures persuade differently. Two primary styles: 1) Principles-first (deductive) — starting with theory, then applications. Common in France, Russia, Germany. 2) Applications-first (inductive) — starting with facts, then conclusions. The French executive who says 'Let me explain why this matters theoretically' frustrates the American who wants the bottom line. To persuade across cultures: understand whether your audience needs 'why' (big picture) or 'how' (practical application). Both are valid — just different.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "persuasion", "deductive", "inductive", "principles-first"], confidence:0.9 },
  { category:"business", title:"Chapter 4: Leadership and Hierarchy", content:"Cultures vary from egalitarian (Denmark, Netherlands, Israel) to hierarchical (Japan, China, Russia, Korea). In egalitarian cultures, the best idea wins regardless of rank. Subordinates call bosses by first names and challenge openly. In hierarchical cultures, authority is respected, decisions come from the top. A Danish manager in Japan will seem weak by asking for input; a Japanese manager in Denmark will seem autocratic by giving orders. Effective leaders adapt to cultural expectations.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "leadership", "hierarchy", "egalitarian", "power-distance"], confidence:0.9 },
  { category:"business", title:"Chapter 5: Who Decides, and How?", content:"Decision-making differs on two dimensions: 1) Consensus vs. top-down, 2) Implementation speed. In consensus cultures (Japan, Sweden), decisions involve everyone and take longer, but implementation is fast. In top-down cultures (China, US), decisions are quick but implementation takes longer. The Ringi system in Japan: proposals circulate to everyone before decisions — slow to decide, fast to execute. American style: fast decisions, slow execution. Both have advantages; understand which style you're working with.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "decision-making", "consensus", "top-down", "ringi"], confidence:0.9 },
  { category:"business", title:"Chapter 6: Two Types of Trust", content:"Trust is built differently across cultures. Two types: 1) Cognitive trust (task-based) — based on reliability. Common in US, UK, Germany. 'I trust you because you deliver.' 2) Affective trust (relationship-based) — based on personal connection. Common in China, Brazil, Saudi Arabia. 'I trust you because I know you.' In relationship-based cultures, business requires personal trust first — long dinners and relationship-building are essential. In task-based cultures, mixing personal and professional seems inefficient.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "trust", "cognitive", "affective", "relationship", "task-based"], confidence:0.9 },
  { category:"business", title:"Chapter 7: Disagreeing Productively", content:"Cultures handle disagreement differently — from confrontational (Israel, France, Russia) to avoidant (Japan, Thailand, Indonesia). In confrontational cultures, debate shows engagement. In avoidant cultures, open disagreement is disrespectful. The French love intellectual debate; the Japanese preserve harmony. Confrontational styles feel aggressive to avoidant cultures; avoidant styles feel dishonest to confrontational cultures. Calibrate your approach — dial directness up or down based on cultural context.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "disagreement", "confrontation", "avoidance", "debate"], confidence:0.9 },
  { category:"business", title:"Chapter 8: Perceptions of Time", content:"Cultures perceive time along a linear-flexible spectrum. Linear-time cultures (Germany, Switzerland, US) treat time as a straight line — fixed schedules, critical punctuality, no interruptions. Flexible-time cultures (India, Brazil, Saudi Arabia) treat time as a flowing river — approximate schedules, normal interruptions, relationships before timeliness. Linear-time people see flex-timers as disorganized; flex-timers see linear people as rigid. The solution: understand the time culture and set clear expectations.", sourceType:"book", sourceName:"The Culture Map by Erin Meyer", tags:["meyer", "time", "linear", "flexible", "scheduling", "punctuality"], confidence:0.85 },
  { category:"psychology", title:"Introduction: The Puzzles of Harlow and Deci", content:"Harry Harlow's monkey experiments and Edward Deci's human studies revealed something puzzling: under certain conditions, rewards and punishments don't work. Monkeys solved puzzles for no reward — they enjoyed mastery for its own sake. Paying people to do puzzles REDUCED their motivation. These findings challenged the fundamental assumption that rewards are the best motivator. There's a mismatch between what science knows about motivation and what business does.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "motivation", "harlow", "deci", "rewards"], confidence:0.9 },
  { category:"psychology", title:"Chapter 1: The Rise and Fall of Motivation 2.0", content:"Motivation has evolved. Motivation 1.0 was biological survival. Motivation 2.0 was carrot-and-stick — reward good, punish bad. This worked for routine tasks in the industrial age. But for creative, conceptual tasks in the 21st century, Motivation 2.0 fails. The Sawyer Effect: when you pay for something enjoyable, you turn play into work. The gap between what science knows (intrinsic motivation drives creativity) and what business does (extrinsic rewards) is the central problem of modern work.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "motivation-2.0", "carrot-stick", "sawyer-effect", "intrinsic"], confidence:0.9 },
  { category:"psychology", title:"Chapter 2: Seven Reasons Carrots and Sticks Don't Work", content:"Seven ways rewards backfire: 1) Extinguish intrinsic motivation, 2) Diminish creative performance, 3) Crush creativity, 4) Crowd out good behavior, 5) Encourage cheating, 6) Become addictive, 7) Foster short-term thinking. 'If-then' rewards (do X, get Y) damage creative work. However, for routine tasks, if-then rewards can work. Rewards for simple, algorithmic tasks are effective; rewards for complex, creative tasks backfire. Unexpected 'now that' rewards don't have the same negative effects.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "rewards", "intrinsic-motivation", "creativity", "if-then"], confidence:0.9 },
  { category:"psychology", title:"Chapter 2a: When Rewards Do Work", content:"There ARE circumstances where if-then rewards work: 1) For routine, algorithmic tasks with clear rules, 2) When rewards are unexpected and offered after the task, 3) When the task is so boring that only external motivation works. The key distinction: algorithmic (following procedures) vs. heuristic (creating something new). Rewards work for algorithmic tasks but undermine heuristic ones. 'Now that' rewards (bonuses given after excellent work) don't have the same negative effects as contingent rewards.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "rewards", "algorithmic", "heuristic", "now-that"], confidence:0.85 },
  { category:"psychology", title:"Chapter 3: Type I and Type X", content:"Two types of motivation: Type X (extrinsic) focuses on external rewards — money, status, praise. Type I (intrinsic) focuses on inherent satisfaction — autonomy, mastery, purpose. Type I behavior is not about rejecting money but recognizing it as a baseline, not the primary motivator. Type I people outperform Type X in the long run. Type I can be learned. The three elements of Type I motivation: AUTONOMY (self-direction), MASTERY (getting better at what matters), PURPOSE (serving something larger than self).", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "type-i", "type-x", "intrinsic", "extrinsic", "autonomy", "mastery", "purpose"], confidence:0.9 },
  { category:"psychology", title:"Chapter 4: Autonomy", content:"Autonomy is our desire to be self-directed. Management is about compliance; autonomy is about engagement. Four dimensions: 1) Task (what we do), 2) Time (when we do it), 3) Technique (how we do it), 4) Team (who we do it with). Atlassian's FedEx Days (24 hours to work on anything) produced extraordinary innovations. Google's 20% time created Gmail and Adsense. Autonomy doesn't mean no accountability — it means self-directed accountability. People given autonomy are more engaged and productive.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "autonomy", "self-direction", "fedex-days", "20-percent-time", "google"], confidence:0.9 },
  { category:"psychology", title:"Chapter 5: Mastery", content:"Mastery is the urge to get better at something that matters. It's painful but deeply satisfying. Three laws: 1) Mastery is a mindset — requires believing you can improve (growth mindset), 2) Mastery is a pain — requires deliberate practice, 3) Mastery is an asymptote — never fully achieved; the pursuit is the point. Flow — complete absorption in challenging but achievable work — is the optimal experience of mastery. Deliberate practice: focusing on weaknesses with immediate feedback. The Goldilocks principle: tasks neither too easy nor too hard.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "mastery", "flow", "deliberate-practice", "growth-mindset"], confidence:0.9 },
  { category:"psychology", title:"Chapter 6: Purpose", content:"Purpose is the yearning to serve something larger than ourselves. Motivation 2.0 focused on profit; Motivation 3.0 focuses on purpose. People with strong purpose are more motivated, productive, and satisfied. Three dimensions: 1) Goals that transcend self-interest, 2) Words reflecting values, 3) Policies putting purpose alongside profit. TOMS Shoes (buy one, give one), Patagonia (environmental mission) show purpose-driven organizations outperform. The purpose motive is a fundamental human drive. Autonomy + Mastery + Purpose = extraordinary results.", sourceType:"book", sourceName:"Drive by Daniel H. Pink", tags:["pink", "purpose", "meaning", "profit", "social-enterprise"], confidence:0.85 }
];
